const req = $input.first().json;
return [{ json: {
  token: (req.headers.authorization || '').replace(/^Bearer\s+/i, '') || req.query?.token,
  timestamp: req.headers['x-caiac-timestamp'],
  signature: req.headers['x-caiac-signature']
}}];

const auth = $input.first().json;
if (!auth.is_caiac_staff) throw new Error('Forbidden: CAIAC staff access required');

const req = $('Receive Request').first().json;
const slug = req.query?.slug;
if (!slug) throw new Error('Missing required query param: slug');

const rawMonths = parseInt(req.query?.months || '3', 10);
const VALID_MONTHS = [1, 3, 6, 12];
const months = VALID_MONTHS.includes(rawMonths) ? rawMonths : 3;

return [{ json: { slug, months } }];

const data = $('Run Analytics Query').first().json.result;
const clientRow = $('Get Client').first().json;
const features = clientRow.features || {};
const months = $('Validate Params').first().json.months;
const slug = $('Validate Params').first().json.slug;

const funnel = data.lead_funnel;
const aiCurrentMonth = data.ai_current_month || 0;

let qualRate = funnel.total > 0 ? funnel.qualified / funnel.total : 0;
let aiEngaged = aiCurrentMonth > 0 ? 1 : 0;
const featuresEnabled = Object.values(features).filter(Boolean).length;
const featuresTotal = Object.keys(features).length;
const featureAdoption = featuresTotal > 0 ? featuresEnabled / featuresTotal : 0;

let qualWeight = 50;
let aiWeight = 30;
const adoptionWeight = 20;

if (features.reviews) {
  const reviewRate = funnel.review_sent > 0 ? funnel.review_responded / funnel.review_sent : 0;
  qualWeight -= 20;
  qualRate = qualRate * (qualWeight / 50) + reviewRate * (20 / 50);
}

if (features.crm_sync) {
  const crmRate = funnel.total > 0 ? funnel.crm_synced / funnel.total : 0;
  aiWeight -= 10;
  aiEngaged = aiEngaged * (aiWeight / 30) + crmRate * (10 / 30);
}

const roi_score = Math.min(100, Math.max(0, Math.round(
  qualRate * qualWeight + aiEngaged * aiWeight + featureAdoption * adoptionWeight
)));

return [{ json: {
  slug,
  months,
  roi_score,
  lead_funnel: funnel,
  ai_trend: data.ai_trend,
  review_funnel: data.review_funnel,
  features
}}];
